-- 11_replace_with_real_schemes.sql
-- Replace temporary scheme rows with real Indian Government schemes

USE gov_scheme_eligibility;

-- Step 1: Remove all temporary "Verified Welfare Scheme" entries
DELETE FROM schemes WHERE scheme_name LIKE 'Verified Welfare Scheme%';

-- Step 2: Insert real Indian Government Schemes (idempotent)

