SELECT * FROM (SELECT 'PM Ujjwala Yojana','PM Ujjwala Yojana','Petroleum & Natural Gas','Provides free LPG connections to women from BPL households to promote clean cooking fuel.','Central','Social Welfare','Women from Below Poverty Line (BPL) households with no existing LPG connection in their name.','Free LPG connection (deposit-free); first refill at subsidized rate.','Aadhaar, BPL/ration card, bank account','https://pmuy.gov.in/',18,NULL,NULL,'Female',1,'official-data',NULL,18,NULL,'Female',NULL,NULL,'none','Aadhaar, BPL/ration card, bank account','https://pmuy.gov.in/') AS tmp
WHERE NOT EXISTS (SELECT 1 FROM schemes WHERE scheme_name = 'PM Ujjwala Yojana');

